frappe.ui.form.on('Job Requisition', {
    onload: function(frm) {
        if (frm.is_new()) {
            frm.set_value('custom_login_user', frappe.session.user);
        }
    }
});

frappe.ui.form.on('Job Opening', {

    custom_requisition_reference: function(frm) {

        if (frm.doc.custom_requisition_reference) {

            frappe.db.get_doc(
                'Job Requisition',
                frm.doc.custom_requisition_reference
            ).then(doc => {

                frm.set_value('job_title', doc.designation || '');
                frm.set_value('designation', doc.designation || '');
                frm.set_value('department', doc.department || '');
                frm.set_value('company', doc.company || '');
                frm.set_value('employment_type', doc.employment_type || '');
                frm.set_value('location', doc.hiring_location || '');

            });

        }
    }

});

// Client Script for Staffing Plan
// Handles: Vacancies × Estimated Cost = Total Estimated Cost
// Sums all rows → Total Estimated Budget

// ── Helper: calculate one row ─────────────────────────
function calculate_row(frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    var vacancies = row.number_of_positions || 0;
    var cost_per_position = row.estimated_cost_per_position || 0;
    var total = vacancies * cost_per_position;

    frappe.model.set_value(cdt, cdn, "total_estimated_cost", total);
    calculate_total_budget(frm);
}

// ── Helper: sum all rows → parent field ──────────────
function calculate_total_budget(frm) {
    var total_budget = 0;

    (frm.doc.staffing_details || []).forEach(function(row) {
        total_budget += (row.total_estimated_cost || 0);
    });

    frm.set_value("total_estimated_budget", total_budget);
    frm.refresh_field("total_estimated_budget");
}

// ── Recalculate all rows (called after Get Job Requisitions) ──
function recalculate_all(frm) {
    (frm.doc.staffing_details || []).forEach(function(row) {
        var vacancies = row.number_of_positions || 0;
        var cost = row.estimated_cost_per_position || 0;
        row.total_estimated_cost = vacancies * cost;
    });

    frm.refresh_field("staffing_details");
    calculate_total_budget(frm);
}

// ── Parent form events ────────────────────────────────
frappe.ui.form.on("Staffing Plan", {

    // Recalculate when form loads
    onload: function(frm) {
        recalculate_all(frm);
    },

    // Recalculate after refresh
    refresh: function(frm) {
        recalculate_all(frm);

        // Override "Get Job Requisitions" button to recalculate after fetch
        frm.page.btn_primary && frm.page.btn_primary.off("click");

        // Hook into after_save to recalculate
        frm.trigger("recalculate_all_rows");
    },

    recalculate_all_rows: function(frm) {
        recalculate_all(frm);
    },

    // Also recalculate after any child table change
    staffing_details_add: function(frm) {
        calculate_total_budget(frm);
    },

    staffing_details_remove: function(frm) {
        calculate_total_budget(frm);
    },
});

// ── Child table events ────────────────────────────────
frappe.ui.form.on("Staffing Plan Detail", {

    // Vacancies changed
    number_of_positions: function(frm, cdt, cdn) {
        calculate_row(frm, cdt, cdn);
    },

    // Estimated Cost Per Position changed
    estimated_cost_per_position: function(frm, cdt, cdn) {
        calculate_row(frm, cdt, cdn);
    },

    // Row added
    staffing_details_add: function(frm, cdt, cdn) {
        calculate_total_budget(frm);
    },

    // Row removed
    staffing_details_remove: function(frm, cdt, cdn) {
        calculate_total_budget(frm);
    },

    // Total Estimated Cost changed (if manually edited)
    total_estimated_cost: function(frm, cdt, cdn) {
        calculate_total_budget(frm);
    },
});

